# PowerShell script to monitor for suspicious new services
# Checks System log for Event ID 7045 (service installed) in last 24 hours

$TimeSpan = (Get-Date).AddDays(-1)
$Events = Get-WinEvent -FilterHashtable @{
    LogName='System'
    ID=7045
    StartTime=$TimeSpan
}

foreach ($Event in $Events) {
    $ServiceName = $Event.Properties[0].Value
    $ServicePath = $Event.Properties[1].Value

    # Alert if service runs from suspicious location
    if ($ServicePath -like "*\Temp\*" -or $ServicePath -like "*\AppData\*") {
        Write-Warning "Suspicious service detected: $ServiceName at $ServicePath"
    }
}
